// test/integration/audit.integration.spec.ts
import { Test, TestingModule } from '@nestjs/testing';
import { INestApplication, ValidationPipe } from '@nestjs/common';
import { PrismaService } from '../../src/prisma/prisma.service';
import { AuditModule } from '../../src/audit/audit.module';
import { AuditService } from '../../src/audit/audit.service';
import { AuditProcessor } from '../../src/audit/audit.processor';
import { AuditController } from '../../src/audit/audit.controller';
import { AuditOutboxStatus, AuditSeverity, AuditSource, Role } from '@prisma/client';

describe('Audit Integration Tests', () => {
  let app: INestApplication;
  let auditService: AuditService;
  let prisma: PrismaService;

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AuditModule],
    })
      .overrideProvider(PrismaService)
      .useValue({
        auditOutbox: {
          create: jest.fn(),
          findMany: jest.fn(),
          update: jest.fn(),
        },
        auditLog: {
          create: jest.fn(),
          findMany: jest.fn(),
          deleteMany: jest.fn(),
        },
        $transaction: jest.fn((cb) => cb()),
      })
      .compile();

    app = moduleFixture.createNestApplication();
    app.useGlobalPipes(new ValidationPipe({ transform: true }));
    
    auditService = moduleFixture.get<AuditService>(AuditService);
    prisma = moduleFixture.get<PrismaService>(PrismaService);
    
    await app.init();
  });

  afterAll(async () => {
    await app.close();
  });

  describe('Audit Log Creation Flow', () => {
    it('should create audit log entry via outbox', async () => {
      const mockCreate = prisma.auditOutbox.create as jest.Mock;
      mockCreate.mockResolvedValue({ id: BigInt(1) });

      await auditService.record({
        entityType: 'User',
        entityId: '123',
        action: 'CREATE',
        severity: AuditSeverity.INFO,
        source: AuditSource.USER,
        actorId: 1,
        actorEmail: 'test@example.com',
        actorRole: Role.ADMIN,
        description: 'Test user created',
      });

      expect(mockCreate).toHaveBeenCalledWith({
        data: expect.objectContaining({
          payload: expect.objectContaining({
            entityType: 'User',
            action: 'CREATE',
          }),
        }),
      });
    });

    it('should handle multiple concurrent audit entries', async () => {
      const mockCreate = prisma.auditOutbox.create as jest.Mock;
      mockCreate.mockResolvedValue({ id: BigInt(1) });

      const promises = Array.from({ length: 10 }, (_, i) =>
        auditService.record({
          entityType: 'Event',
          entityId: String(i),
          action: 'CREATE',
        }),
      );

      await Promise.all(promises);

      expect(mockCreate).toHaveBeenCalledTimes(10);
    });
  });

  describe('Audit Query Flow', () => {
    it('should query audit logs with filters', async () => {
      const mockFindMany = prisma.auditLog.findMany as jest.Mock;
      const mockData = [
        {
          id: BigInt(1),
          entityType: 'User',
          action: 'CREATE',
          severity: AuditSeverity.INFO,
        },
      ];
      mockFindMany.mockResolvedValue(mockData);

      const controller = app.get<AuditController>(AuditController);
      const result = await controller.list({ entityType: 'User' });

      expect(mockFindMany).toHaveBeenCalledWith({
        where: { entityType: 'User' },
        orderBy: { occurredAt: 'desc' },
        take: 50,
        skip: 0,
      });
      expect(result).toEqual(mockData);
    });

    it('should support pagination', async () => {
      const mockFindMany = prisma.auditLog.findMany as jest.Mock;
      mockFindMany.mockResolvedValue([]);

      const controller = app.get<AuditController>(AuditController);
      await controller.list({ page: 2, limit: 10 });

      expect(mockFindMany).toHaveBeenCalledWith({
        where: {},
        orderBy: { occurredAt: 'desc' },
        take: 10,
        skip: 10,
      });
    });
  });

  describe('Audit Processing Flow', () => {
    it('should process outbox entries', async () => {
      const mockFindMany = prisma.auditOutbox.findMany as jest.Mock;
      const mockUpdate = prisma.auditOutbox.update as jest.Mock;
      const mockCreate = prisma.auditLog.create as jest.Mock;

      mockFindMany.mockResolvedValue([
        {
          id: BigInt(1),
          payload: { entityType: 'User', action: 'CREATE' },
          status: AuditOutboxStatus.PENDING,
          attempts: 0,
        },
      ]);
      mockCreate.mockResolvedValue({ id: BigInt(1) });
      mockUpdate.mockResolvedValue({});

      const processor = app.get<AuditProcessor>(AuditProcessor);
      await processor.process();

      expect(mockCreate).toHaveBeenCalled();
      expect(mockUpdate).toHaveBeenCalledWith({
        where: { id: BigInt(1) },
        data: {
          status: AuditOutboxStatus.PROCESSED,
          processedAt: expect.any(Date),
        },
      });
    });

    it('should handle processing failures', async () => {
      const mockFindMany = prisma.auditOutbox.findMany as jest.Mock;
      const mockUpdate = prisma.auditOutbox.update as jest.Mock;
      const mockCreate = prisma.auditLog.create as jest.Mock;

      mockFindMany.mockResolvedValue([
        {
          id: BigInt(1),
          payload: { entityType: 'User', action: 'CREATE' },
          status: AuditOutboxStatus.PENDING,
          attempts: 0,
        },
      ]);
      mockCreate.mockRejectedValue(new Error('Database error'));
      mockUpdate.mockResolvedValue({});

      const processor = app.get<AuditProcessor>(AuditProcessor);
      await processor.process();

      expect(mockUpdate).toHaveBeenCalledWith({
        where: { id: BigInt(1) },
        data: {
          attempts: 1,
          status: AuditOutboxStatus.FAILED,
          lastError: expect.any(String),
        },
      });
    });
  });
});
